from collections import Counter

class Solution:
    def minSteps(self, s, t):
        cs = Counter(s)
        ct = Counter(t)
        letters = set(cs) | set(ct)
        return sum(abs(cs.get(c, 0) - ct.get(c, 0)) for c in letters)

