var minSteps = function(s, t) {
    const cs = new Array(26).fill(0);
    const ct = new Array(26).fill(0);
    for (const ch of s) cs[ch.charCodeAt(0) - 97]++;
    for (const ch of t) ct[ch.charCodeAt(0) - 97]++;
    let total = 0;
    for (let i = 0; i < 26; i++) total += Math.abs(cs[i] - ct[i]);
    return total;
};
